            ['id' => 18, 'label' => 'المسيرة الأدبية',  'value' => 'أتمّ يوسف دراسته في القاهرة وعاد إلى الكويت حيث عمل دبلوماسياً لسنوات ظلّ يكتب خلالها بعيداً عن الأضواء. أصدر أول رواياته في السبعينيات وكانت سابقة لعصرها في تناول الهوية الخليجية أدبياً. أسلوبه يجمع الشعر بالسرد في نسيج نادر.',                    'author_id' => 5, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
            ['id' => 19, 'label' => 'الإنجازات',        'value' => 'نال يوسف جائزة الدولة الكويتية للتفوق في الآداب وجائزة البابطين للإبداع الشعري. صدرت أعماله الكاملة في عشرة مجلدات عام ألفين. يُعدّ مرجعاً في الرواية الخليجية وكرّست له عدة رسائل دكتوراه في جامعات عربية.',                                               'author_id' => 5, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
