            ['id' => 34, 'label' => 'المسيرة الأدبية',  'value' => 'تخرج طارق من جامعة الخرطوم قسم الفلسفة وعمل معلماً في القرى النائية قبل أن يُصدر مجموعته الشعرية الأولى التي أحدثت موجة في الوسط الثقافي السوداني. تحوّل للرواية في العقد الأول من الألفية الثالثة فأتت رواياته حاملة صوت الأرض السودانية بكل ألوانها.',    'author_id' => 9, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
            ['id' => 35, 'label' => 'الإنجازات',        'value' => 'نال طارق جائزة الطيب صالح للرواية وجائزة اتحاد الكتاب العرب. يُعدّ أحد أبرز الأصوات الأدبية الأفريقية الناطقة بالعربية. تُرجمت روايته الرئيسية للإنجليزية والفرنسية. اختير عضواً في مجلس إدارة رابطة الأدباء العرب الدولية.',                               'author_id' => 9, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
            ['id' => 36, 'label' => 'خاتمة المسيرة',   'value' => 'يُواصل طارق البشير الكتابة من الخرطوم رغم كل الاضطرابات، ويقول في لقاء أخير: "الكتابة عندي صلاة، والأرض السودانية أعمق من أي نهر تظنه تعرفه".',                                                                                                               'author_id' => 9, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
            // Author 10: فاطمة العمري
            ['id' => 37, 'label' => 'السيرة الذاتية',   'value' => 'وُلدت فاطمة العمري في يونيو عام ألف وتسعمئة وتسعين في مراكش المغربية، في حي العتيقة حيث تتقاطع روائح البهارات والنحاس المطروق وأصوات الحكواتيين. كانت جدتها تعدّها للكتابة دون أن تعلم.',                                                                    'author_id' => 10, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
            ['id' => 38, 'label' => 'المسيرة الأدبية',  'value' => 'درست فاطمة الأدب العربي المقارن في الرباط ثم حصلت على منحة لإتمام الدراسات العليا في مدريد. أصدرت روايتها الأولى وهي في الثامنة والعشرين فأدهشت النقاد بنضجها السردي. تكتب بالعربية والفرنسية وتؤمن أن لكل لغة جزءاً منها لا تستطيع الأخرى الوصول إليه.',  'author_id' => 10, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
            ['id' => 39, 'label' => 'الإنجازات',        'value' => 'فازت فاطمة بجائزة المغرب للكتاب وجائزة كتارا للرواية العربية وهي من أصغر الفائزين بها. وصلت إلى القائمة القصيرة لبوكر العربية مرتين متتاليتين. تُترجم أعمالها للإسبانية والإيطالية والبرتغالية. تُلقي محاضرات في مهرجانات أدبية في أوروبا وأمريكا اللاتينية.', 'author_id' => 10, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
            ['id' => 40, 'label' => 'خاتمة المسيرة',   'value' => 'فاطمة العمري في بداية مسيرة يتوقع لها النقاد أن تكون من الأصوات الأكثر تأثيراً في جيلها، وأعلنت عن مشروع روائي ضخم يستعيد تاريخ المغرب من خلال عيون عشر نساء عبر عشرة قرون.',                                                                              'author_id' => 10, 'created_at' => '2022-01-01 00:00:00', 'updated_at' => '2022-01-01 00:00:00'],
        ];

        foreach ($details as &$detail) {
